-- ----------------------------
-- Table structure for eb_overseas_excel_field_mapping
-- ----------------------------
DROP TABLE IF EXISTS `eb_overseas_excel_field_mapping`;
CREATE TABLE `eb_overseas_excel_field_mapping`  (
  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `store_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '门店ID (日志.txt 第一列)',
  `platform_id` tinyint(3) UNSIGNED NOT NULL DEFAULT 0 COMMENT '平台ID 16=TikTok 24=Shopee 27=Lazada',
  `order_type` tinyint(3) UNSIGNED NOT NULL DEFAULT 0 COMMENT '订单类型 18=订单 19=退货退款 20=联盟达人 21=联盟服务商 22=结算表 23=未结算 25=广告费 26=到账资金',
  `table_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT 'MySQL 目标表名',
  `db_field_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT 'MySQL 字段名 (归一化后)',
  `excel_field_name` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT '' COMMENT 'Excel 原始表头 (翻译前, 大小写敏感, 保留 FBT fulfillment fee vs FBT Fulfillment Fee 两种写法)',
  `excel_field_name_en` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Excel 表头英文翻译 (中文表头才有值)',
  `is_existing_column` tinyint(3) UNSIGNED NOT NULL DEFAULT 1 COMMENT '1=现有列 0=新列 (本次 ALTER 新增)',
  `rule_version` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'v1' COMMENT '归一化规则版本, 规则变更时升级',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uniq_store_order_db_excel`(`store_id`, `order_type`, `db_field_name`, `excel_field_name`(200)) USING BTREE,
  INDEX `idx_store_order`(`store_id`, `order_type`) USING BTREE,
  INDEX `idx_table_db`(`table_name`, `db_field_name`) USING BTREE,
  INDEX `idx_db_field`(`db_field_name`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5862 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'Excel 字段 ↔ MySQL 字段映射表' ROW_FORMAT = Dynamic;

